const rows = $input.all().map(i => i.json).map(r => ({
  ...r,
  duration_min: Number(r.duration_min || 0),
  has_quote:   Boolean(r.has_quote),
  has_session: Boolean(r.has_session),
}));

const now = new Date();
const total        = rows.length;
const completadas  = rows.filter(r => r.status === 'completed').length;
const confirmadas  = rows.filter(r => r.status === 'confirmed').length;
const canceladas   = rows.filter(r => r.status === 'cancelled').length;
const no_shows     = rows.filter(r => r.status === 'no_show').length;
const con_presupuesto = rows.filter(r => r.has_quote).length;
const con_sesion      = rows.filter(r => r.has_session).length;
const sin_atender     = rows.filter(r => ['scheduled','confirmed'].includes(r.status) && new Date(r.start_datetime) < now).length;
const duracion_promedio_min = total ? Math.round(rows.reduce((s, r) => s + r.duration_min, 0) / total) : 0;

// by_status
const statusMap = {};
for (const r of rows) statusMap[r.status] = (statusMap[r.status] || 0) + 1;
const by_status = Object.entries(statusMap)
  .sort((a, b) => b[1] - a[1])
  .map(([status, count]) => ({ status, count, pct: total ? Number((count / total * 100).toFixed(1)) : 0 }));

// by_doctor
const ALL_STATUSES = ['completed','arrived','in_progress','confirmed','scheduled','no_show','cancelled'];
const docMap = {};
for (const r of rows) {
  if (!docMap[r.doctor_name]) {
    docMap[r.doctor_name] = { total: 0 };
    for (const s of ALL_STATUSES) docMap[r.doctor_name][s] = 0;
  }
  docMap[r.doctor_name].total++;
  if (ALL_STATUSES.includes(r.status)) docMap[r.doctor_name][r.status]++;
}
const by_doctor = Object.entries(docMap)
  .sort((a, b) => b[1].total - a[1].total)
  .map(([doctor_name, d]) => ({ doctor_name, ...d, tasa_completadas: d.total ? Number((d.completed / d.total * 100).toFixed(1)) : 0 }));

// by_period
const periodMap = {};
for (const r of rows) {
  const p = (r.periodo || '').substring(0, 10);
  if (!periodMap[p]) {
    periodMap[p] = { total: 0 };
    for (const s of ALL_STATUSES) periodMap[p][s] = 0;
  }
  periodMap[p].total++;
  if (ALL_STATUSES.includes(r.status)) periodMap[p][r.status]++;
}
const by_period = Object.entries(periodMap)
  .sort((a, b) => a[0].localeCompare(b[0]))
  .map(([periodo, d]) => ({ periodo, ...d }));

// by_calendar
const calMap = {};
for (const r of rows) {
  if (!calMap[r.calendar_name]) {
    calMap[r.calendar_name] = { total: 0 };
    for (const s of ALL_STATUSES) calMap[r.calendar_name][s] = 0;
  }
  calMap[r.calendar_name].total++;
  if (ALL_STATUSES.includes(r.status)) calMap[r.calendar_name][r.status]++;
}
const by_calendar = Object.entries(calMap)
  .sort((a, b) => b[1].total - a[1].total)
  .map(([calendar_name, d]) => ({ calendar_name, ...d, tasa: d.total ? Number((d.completed / d.total * 100).toFixed(1)) : 0 }));

return [{ json: {
  summary: {
    total_citas: total, completadas, confirmadas, canceladas, no_shows,
    con_presupuesto, con_sesion, sin_atender,
    tasa_completadas:     total ? Number((completadas  / total * 100).toFixed(1)) : 0,
    tasa_canceladas:      total ? Number((canceladas   / total * 100).toFixed(1)) : 0,
    tasa_con_presupuesto: total ? Number((con_presupuesto / total * 100).toFixed(1)) : 0,
    duracion_promedio_min
  },
  by_status, by_doctor, by_period, by_calendar, rows
} }];

const REASON_LABELS = { late: 'Llegó tarde', in_time: 'Canceló a tiempo', no_notice: 'Sin aviso', by_doctor: 'Por el doctor', by_clinic: 'Por la clínica', other: 'Otro motivo', reschedule: 'Reprogramó' };
const rows = $input.all().map(i => i.json);
const total = rows.length;

// by_reason
const reasonMap = {};
for (const r of rows) {
  const reason = r.cancellation_reason || 'other';
  reasonMap[reason] = (reasonMap[reason] || 0) + 1;
}
const by_reason = Object.entries(reasonMap)
  .sort((a, b) => b[1] - a[1])
  .map(([reason, count]) => ({ reason, label: REASON_LABELS[reason] || reason, count, pct: total ? Number((count / total * 100).toFixed(1)) : 0 }));

// by_doctor
const docMap = {};
for (const r of rows) {
  const name = r.doctor_name || 'Sin asignar';
  docMap[name] = (docMap[name] || 0) + 1;
}
const by_doctor = Object.entries(docMap)
  .sort((a, b) => b[1] - a[1])
  .map(([doctor_name, count]) => ({ doctor_name, count, pct: total ? Number((count / total * 100).toFixed(1)) : 0 }));

// by_patient
const patMap = {};
for (const r of rows) {
  const name = r.patient_name || 'Sin paciente';
  if (!patMap[name]) patMap[name] = { count: 0, phone_number: r.phone_number || '' };
  patMap[name].count++;
}
const by_patient = Object.entries(patMap)
  .sort((a, b) => b[1].count - a[1].count)
  .map(([patient_name, d]) => ({ patient_name, ...d }));

// by_service
const svcMap = {};
for (const r of rows) {
  const svc = r.service_name || 'Sin servicio';
  svcMap[svc] = (svcMap[svc] || 0) + 1;
}
const by_service = Object.entries(svcMap)
  .sort((a, b) => b[1] - a[1])
  .map(([service_name, count]) => ({ service_name, count, pct: total ? Number((count / total * 100).toFixed(1)) : 0 }));

// by_calendar
const calMap = {};
for (const r of rows) {
  const cal = r.calendar_name || 'Sin consultorio';
  calMap[cal] = (calMap[cal] || 0) + 1;
}
const by_calendar = Object.entries(calMap)
  .sort((a, b) => b[1] - a[1])
  .map(([calendar_name, count]) => ({ calendar_name, count, pct: total ? Number((count / total * 100).toFixed(1)) : 0 }));

// by_period
const periodMap = {};
for (const r of rows) {
  const p = (r.start_datetime || '').substring(0, 10);
  periodMap[p] = (periodMap[p] || 0) + 1;
}
const by_period = Object.entries(periodMap)
  .sort((a, b) => a[0].localeCompare(b[0]))
  .map(([periodo, count]) => ({ periodo, count }));

const top_reason = by_reason[0]?.reason || '';
const top_reason_label = REASON_LABELS[top_reason] || top_reason;
const top_doctor = by_doctor[0]?.doctor_name || '';
const top_patient = by_patient[0]?.patient_name || '';
const top_service = by_service[0]?.service_name || '';

return [{ json: {
  summary: { total, top_reason, top_reason_label, top_doctor, top_patient, top_service },
  by_reason, by_doctor, by_patient, by_service, by_calendar, by_period, rows
} }];
